import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import "../../styles/welcome.css";

export default function WelcomePage() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  if (!user) return null;

  const goNext = () => {
    if (user.accountType !== "driver") return navigate("/driver/trips");
    if (!user.carDetailsCompleted) return navigate("/driver/car-details");
    if (!user.idDocumentUploaded) return navigate("/driver/verification-consent");
    if (!user.faceVerified) return navigate("/driver/face-verification");
    return navigate("/driver/trips");
  };

  return (
    <div className="welcome-hero-page">
      <div className="welcome-hero-card">
        <div className="hero-arc hero-arc-left" />
        <div className="hero-arc hero-arc-right" />

        <div className="hero-chip">SecureRide Verification</div>

        <h1 className="hero-title">
          Welcome, {user.fullNames || "Driver"} <span>👋</span>
        </h1>

        <p className="hero-subtitle">
          Your account is active. Complete the remaining verification steps to continue to trips.
        </p>

        <div className="hero-status-row">
          <div className="hero-status"><span>Account:</span> <strong>{user.accountType}</strong></div>
          <div className="hero-status"><span>Car details:</span> <strong>{user.carDetailsCompleted ? "✅ Complete" : "⏳ Pending"}</strong></div>
          <div className="hero-status"><span>ID upload:</span> <strong>{user.idDocumentUploaded ? "✅ Uploaded" : "⏳ Pending"}</strong></div>
          <div className="hero-status"><span>Face verification:</span> <strong>{user.faceVerified ? "✅ Verified" : "⏳ Pending"}</strong></div>
        </div>

        <div className="hero-actions">
          <button className="hero-btn primary" onClick={goNext}>
            Continue
          </button>
          <button className="hero-btn ghost" onClick={logout}>
            Logout
          </button>
        </div>
      </div>
    </div>
  );
}
